"""
MKT Original Language Commentary — Psalms chapters 80–85 (86 verses)
Run: python3 scripts/zc-original-psalms-80-85.py

Key decisions in this range:
- Ps 80: triple refrain (vv3/7/19) as the structural pillar; ben-ʾādām (v17)
  noted as carrying messianic valence; the vine allegory traced to Isa 5/Jer 2
- Ps 81: divine speech begins at v5b (śĕpat lōʾ-yādaʿtî ʾeshmaʿ); Decalogue
  preamble cited verbatim (v10 = Exod 20:2); v12 ʾăshallĕḥêhû parallels Rom 1:24
- Ps 82: ʾĕlōhîm in vv1,6 treated as divine-council beings (not human judges);
  v6 cited in John 10:34-35 — Jesus's argument preserved; kĕʾādām (v7) as
  "like the man [Adam]" vs "like men" left as deliberate polysemy
- Ps 83: 10-nation coalition covers the compass of Israel's enemies (vv6-8);
  redemptive goal of imprecation (vv16-18) treated as climax not afterthought
- Ps 84: three ʾashrê beatitudes (vv4,5,12); ʿēmeq habbākhāʾ as balsam valley
  vs weeping valley (both readings noted); shemesh ûmāgēn unusual solar epithet
- Ps 85: v10 (ḥesed-ʾemet meet / ṣedeq-shālôm kiss) treated as theological
  climax of the psalm; four attributes as personified covenant virtues
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

# INTENT: mkt-original for Psalms 80-85 — the Asaph laments (Ps80-83) and the
#   Korah pilgrim/restoration psalms (Ps84-85), spanning vine allegory (Ps80),
#   festival-divine-speech (Ps81), divine-council judgment (Ps82), coalition
#   lament (Ps83), pilgrim longing (Ps84), and covenant-attributes theology (Ps85).
# CHANGE? If data/commentary/mkt-original/psalms.json structure changes, update
#   load_comm/save_comm per Z_COMMENTARY_SCRIPT_GUIDE.md.
# VERIFY: python3 -c "import json; d=json.load(open('data/commentary/mkt-original/psalms.json')); print([len(d.get(str(c),{})) for c in range(80,86)])"

PSALMS = {
  "80": {
    "1": '<p>The superscription assigns Psalm 80 to Asaph and specifies the tune <em>shôshannîm ʿêdût</em> (Lilies of the Covenant). The opening address is unique in the Psalter: <strong>רֹעֵה יִשְׂרָאֵל הַאֲזִינָה</strong> (<em>rōʿēh yiśrāʾêl hāʾăzînāh</em>, "O Shepherd of Israel, give ear!") — <em>rōʿēh</em>: the participle of <em>rāʿāh</em> (to shepherd/feed/tend) used as a divine title (Gen 48:15 — Jacob: "the God who has been my shepherd all my life"; Ps 23:1). <strong>נֹהֵג כַּצֹּאן יוֹסֵף</strong> (<em>nōhêg kaṣṣōʾn yôsêp</em>, "you who lead Joseph like a flock") — <em>nāhag</em>: to lead, to drive (the shepherd driving the flock — Ps 78:52). Joseph stands for the northern tribes (Ephraim, Manasseh, Benjamin — v2). <strong>יֹשֵׁב הַכְּרוּבִים הוֹפִיעָה</strong> (<em>yōshêb hakkĕrûbîm hôpîʿāh</em>, "you who are enthroned above the cherubim, shine forth!") — the ark-presence language (1 Sam 4:4; 2 Sam 6:2). <em>Hôpîʿ</em> (hiphil: to shine forth in blazing light — Deut 33:2): the cherubim-enthroned God summoned to shine for his flock.</p>',
    "2": '<p><strong>לִפְנֵי אֶפְרַיִם וּבִנְיָמִן וּמְנַשֶּׁה</strong> (<em>lipnê ʾeprayim ûbinyāmîn ûmĕnashsheh</em>, "before Ephraim and Benjamin and Manasseh") — the three Rachel tribes grouped together in the wilderness march behind the ark (Num 10:21-24). The petition calls the Shepherd to march at the front of his flock again, as at the Exodus. <strong>עוֹרְרָה אֶת-גְּבוּרָתְךָ וּלְכָה לִישֻׁעָתָה לָּנוּ</strong> (<em>ʿôrĕrāh ʾet-gĕbûrātĕkā ûlĕkāh lîshûʿātāh llānû</em>, "stir up your might and come to save us!") — <em>ʿûr</em> (piel: to rouse from inactivity — Ps 7:6: "rise up against the rage of my enemies"). The petition treats God as a sleeping or resting warrior who must be awakened to battle.</p>',
    "3": '<p><strong>אֱלֹהִים הֲשִׁיבֵנוּ וְהָאֵר פָּנֶיךָ וְנִוָּשֵׁעָה</strong> (<em>ʾĕlōhîm hăshîbênû wĕhāʾêr pānêkā wĕniwwāshêʿāh</em>, "Restore us, O God; let your face shine on us, that we may be saved!") — the first occurrence of the three-part refrain that structures the whole psalm (repeated at vv7 and 19 with escalating divine titles). <em>Shûb</em> (hiphil: to cause to return/restore — dense with covenant meaning: both physical return and inner restoration of the relationship). <em>Hāʾêr pānêkā</em>: "let your face shine" — the Aaronic blessing (Num 6:25: <em>yāʾêr YHWH pānāyw ʾêlêkā</em>). The shining divine face is both the sign of favor and the source of salvation.</p>',
    "4": '<p><strong>יְהוָה אֱלֹהִים צְבָאוֹת עַד-מָתַי עָשַׁנְתָּ בִּתְפִלַּת עַמֶּךָ</strong> (<em>yĕhwāh ʾĕlōhîm ṣĕbāʾôt ʿad-mātay ʿāshantāh bĕtĕpillat ʿammekā</em>, "O LORD God of hosts, how long will you smolder against your people\'s prayers?") — <em>ʿāshantāh</em>: second-person qal perfect of <em>ʿāshan</em> (to smoke, to smolder — Ps 74:1; Deut 29:20). God\'s anger described as smoke. The extraordinary claim: even the people\'s prayers provoke the divine anger rather than appeasing it. <em>ʿAd-mātay</em> (how long?) — the standard lament-time challenge (Ps 13:1-2; 74:10; 79:5).</p>',
    "5": '<p><strong>הֶאֱכַלְתָּם לֶחֶם דִּמְעָה</strong> (<em>heʾĕkhaltām leḥem dimʿāh</em>, "you have fed them with the bread of tears") — <em>dimʿāh</em>: tears (from <em>dāmaʿ</em>: to weep). The covenant meal subverted: instead of the feast of Ps 23:5 or the honey of Deut 32:13-14, God gives bread made of tears. <strong>וַתַּשְׁקֵמוֹ בִּדְמָעוֹת שָׁלִישׁ</strong> (<em>wattashqêmô bĕdĕmāʿôt shālîsh</em>, "and you gave them tears to drink in full measure") — <em>shālîsh</em>: a measure of capacity — either a triple portion or a standard measure (either way, abundance is what was meant to sustain). The one who gave water from the rock (Exod 17) now gives tears in measured abundance; the wilderness provision inverted.</p>',
    "6": '<p><strong>תְּשִׂימֵנוּ מָדוֹן לִשְׁכֵנֵינוּ</strong> (<em>tĕśîmênû mādon lishkênênû</em>, "you make us an object of contention for our neighbors") — <em>mādon</em>: strife, contention (from <em>dîn</em>: to judge/contend). Israel has become the disputed object that neighbors fight over as a bone of contention, not as a prize. <strong>וְאֹיְבֵינוּ יִלְעֲגוּ-לָמוֹ</strong> (<em>wĕʾôyĕbênû yilʿăgû-lāmô</em>, "and our enemies mock us") — <em>lāʿag</em>: to mock, to deride (Ps 79:4; 44:13-14). The nations meant to see Israel as proof of YHWH\'s power instead see proof of the Shepherd\'s abandonment of his flock.</p>',
    "7": '<p>The refrain at its midpoint with a fuller divine title: <strong>אֱלֹהִים צְבָאוֹת הֲשִׁיבֵנוּ</strong> (<em>ʾĕlōhîm ṣĕbāʾôt hăshîbênû</em>, "Restore us, O God of hosts") — <em>ṣĕbāʾôt</em> (of hosts/armies — YHWH as commander of the heavenly army) escalates the appeal: if God is Lord of all armies, why are enemies mocking his people? <strong>וְהָאֵר פָּנֶיךָ וְנִוָּשֵׁעָה</strong> — the refrain unchanged: face-shining as the singular petition. The structural repetition is itself the liturgical act of persistence before God that the psalm dramatizes.</p>',
    "8": '<p><strong>גֶּפֶן מִמִּצְרַיִם תַּסִּיעַ</strong> (<em>gepen miMMiṣrayim tassîaʿ</em>, "you uprooted a vine from Egypt") — <em>nāsaʿ</em> (hiphil: to uproot, to move camp): the Exodus as agricultural transplanting. The vine-allegory of Israel is a major prophetic tradition: Isa 5:1-7; Jer 2:21 ("I planted you as a choice vine — how then did you turn wild?"); Ezek 17; 19. <strong>תְּגָרֵשׁ גּוֹיִם וַתִּטָּעֶהָ</strong> (<em>tĕgārêsh gôyim wattittāʿehā</em>, "you drove out the nations and planted it") — <em>gāresh</em>: to drive out, expel (the same verb for Adam\'s expulsion from Eden — Gen 3:24). The vintner who cleared the land and planted with care is the same God whose face the Psalmist begs to shine (v7).</p>',
    "9": '<p><strong>פִּנִּיתָ לְפָנֶיהָ</strong> (<em>pinnîtā lĕpānêhā</em>, "you cleared the ground before it") — <em>pinnāh</em> (piel: to clear away, remove obstacles — stone-clearing before planting). <strong>וַתַּשְׁרֵשׁ שָׁרָשֶׁיהָ וַתְּמַלֵּא-אָרֶץ</strong> (<em>wattashrêsh shārāshêhā wattĕmallêʾ-ʾāreṣ</em>, "it took deep root and filled all the land!") — <em>shāresh</em> (piel: to take root — denominative from <em>shoresh</em>: root). The transplanted vine established itself and expanded to fill the land — the Conquest and the settlement under David and Solomon at its maximum extent.</p>',
    "10": '<p><strong>כָּסּוּ הָרִים צִלָּהּ</strong> (<em>kāssû hārîm ṣillāh</em>, "the mountains were covered with its shade") — a vine\'s shadow covering mountains: hyperbolic growth imagery for the empire at its maximum extent. <strong>וַעֲנָפֶיהָ אַרְזֵי-אֵל</strong> (<em>waʿănāpêhā ʾarzê-ʾêl</em>, "its branches were like the cedars of God") — <em>ʾarzê-ʾêl</em>: the divine superlative — the cedars of Lebanon (the tallest trees of the ancient Near East — 1 Kgs 5:6; Ps 104:16). Vine-branches reaching the scale of Lebanon\'s cedars: the empire of David-Solomon at its most imposing.</p>',
    "11": '<p><strong>תְּשַׁלַּח קְצִירֶהָ עַד-יָם</strong> (<em>tĕshallah qĕṣîrehā ʿad-yām</em>, "it sent its branches to the sea") — the western border (the Mediterranean). <strong>וְאֶל-נָהָר יוֹנְקוֹתֶיהָ</strong> (<em>wĕʾel-nāhār yônqôtêhā</em>, "and its shoots to the River") — <em>hannāhār</em>: the Euphrates (the eastern boundary — Gen 15:18; Deut 11:24). The vine at its maximum extent reaches sea to river — the full territorial promise of Abraham\'s covenant. This is the vineyard at its height before the allegory turns to devastation.</p>',
    "12": '<p><strong>לָמָּה פָּרַצְתָּ גְדֵרֶיהָ</strong> (<em>lāmmāh pāraṣtā gĕdêrehā</em>, "why have you broken down its walls?") — <em>pāraṣ</em>: to breach (2 Kgs 25:10). The gardener who planted the vine is the same one who has torn down its protective walls — the lament confronts the theodicy directly. <strong>וְאָרוּהָ כָּל-עֹבְרֵי דָרֶךְ</strong> (<em>wĕʾārûhā kol-ʿōbĕrê dārek</em>, "so that all who pass along the road pluck its fruit!") — <em>ʾārah</em>: to gather/pluck fruit. Without walls, the vineyard is exposed to random exploitation by anyone passing — the opposite of the careful cultivation of the vintner.</p>',
    "13": '<p><strong>יְכַרְסְמֶנָּה חֲזִיר מִיָּעַר</strong> (<em>yĕkharsĕmennāh ḥăzîr miyyāʿar</em>, "the boar from the forest ravages it") — <em>kārasam</em>: to gnaw, to root up (the rooting behavior of a wild pig that tears up vineyards from below, uprooting the roots themselves). <em>Ḥăzîr miyyāʿar</em>: the wild boar from the forest — not a thief stealing fruit but a beast destroying the root system. <strong>וְזִיז שָׂדַי יִרְעֶנָּה</strong> (<em>wĕzîz śāday yirʿennāh</em>, "and the wild creatures of the field feed on it") — <em>zîz</em>: the swarming wildlife (Ps 50:11). The boar and the field-creatures together represent the foreign nations: large powers that uproot and small opportunists that graze what remains.</p>',
    "14": '<p><strong>אֱלֹהִים צְבָאוֹת שׁוּב-נָא</strong> (<em>ʾĕlōhîm ṣĕbāʾôt shûb-nāʾ</em>, "Return, we pray, O God of hosts!") — <em>shûb</em> + <em>nāʾ</em> (entreating particle): the verb that described Israel\'s restoration (v1) now turned toward God: "you turn, return!" <strong>הַבֵּט מִשָּׁמַיִם וּרְאֵה</strong> (<em>habbêṭ mishshāmayim ûrĕʾêh</em>, "look down from heaven, see!") — <em>nābaṭ</em> (hiphil: to look down from a height). <strong>וּפְקֹד גֶּפֶן זֹאת</strong> (<em>ûpĕqōd gepen zōʾt</em>, "and tend this vine!") — <em>pāqad</em>: to visit, attend to (the word covers both "to punish" and "to care for with blessing" — context demands: give the attending care of a gardener).</p>',
    "15": '<p><strong>וְכַנָּה אֲשֶׁר-נָטְעָה יְמִינֶךָ</strong> (<em>wĕkhannāh ʾăsher-nāṭĕʿāh yĕmînekā</em>, "the stock your right hand planted") — <em>kānāh</em>: a root-stock, the base of a vine from which shoots grow (a rare agricultural term). <em>Yĕmîn</em>: the right hand of power (Ps 17:7; 20:6). God planted the vine with his own right hand — the vintner\'s personal investment is the basis of the appeal. <strong>וְעַל-בֵּן אִמַּצְתָּ לָּךְ</strong> (<em>wĕʿal-bên ʾimmaṣtā llāk</em>, "and the son you made strong for yourself") — <em>ben</em>: son/branch (possibly both — the shoot of the vine and the royal son). <em>ʾĀmēṣ</em> (piel: to make strong, establish). The "son" designation introduces a royal dimension developed in v17.</p>',
    "16": '<p><strong>שְׂרֻפָה בָאֵשׁ כְּסוּחָה</strong> (<em>śĕrûpāh bāʾêsh kĕsûḥāh</em>, "it is burned with fire and cut down!") — <em>sāḥāh</em>: to cut away, prune (catastrophic pruning — the opposite of the careful tending requested in v14). Burned and cut: both the vine\'s surface and its roots destroyed. <strong>מִגַּעֲרַת פָּנֶיךָ יֹאבֵדוּ</strong> (<em>miggaʿărat pānêkā yōʾbêdû</em>, "may they perish at the rebuke of your face!") — <em>gaʿārah</em>: the divine rebuke (Ps 76:6 — the rebuke that put Sennacherib\'s army to sleep; Ps 18:15 — the rebuke that exposed the sea-bottom). The Psalmist turns the divine rebuke from its current target (the vine/Israel) toward the enemies who burned and cut.</p>',
    "17": '<p><strong>תְּהִי-יָדְךָ עַל-אִישׁ יְמִינֶךָ עַל-בֶּן-אָדָם</strong> (<em>tĕhî-yādĕkā ʿal-ʾîsh yĕmînekā ʿal-ben-ʾādām</em>, "let your hand be on the man of your right hand, the son of man!") — <em>ʾîsh yĕmînekā</em>: the man at God\'s right hand (the position of supreme honor — Ps 110:1). <em>Ben-ʾādām</em>: son of man/son of Adam (used in Ps 8:4 for human frailty — here with "whom you made strong for yourself"). In Dan 7:13 the eschatological figure who comes before the Ancient of Days receives universal dominion; Jesus\'s self-designation as the Son of Man activates this cluster. The vine\'s son/shoot (v15) is now the royal <em>ben-ʾādām</em> at God\'s right hand. <strong>אִמַּצְתָּ לָּךְ</strong> (<em>ʾimmaṣtā llāk</em>, "whom you have made strong for yourself") — same verb and object as v15, forming an inclusion: the vine\'s strength and the Son of Man\'s strength are the same divine action.</p>',
    "18": '<p><strong>וְלֹא-נָסוֹג מִמֶּךָּ</strong> (<em>wĕlōʾ-nāsôg mimmekā</em>, "then we will not turn back from you!") — <em>nāsôg</em>: to retreat, to turn back (Ps 44:18: "we have not departed from you"; Ps 78:57: the ancestors turned away like a faithless bow). The vow: if God restores the vine through the son/man, Israel will not retreat from the restored covenant. <strong>תְּחַיֵּנוּ וּבְשִׁמְךָ נִקְרָא</strong> (<em>tĕḥayyênû ûbĕshimĕkā niqrāʾ</em>, "give us life, and we will call on your name!") — <em>ḥāyāh</em> (piel: to give life — the quickening of the dead vine). To call on the divine name is the defining act of covenant worship (Gen 4:26; 12:8).</p>',
    "19": '<p>The final refrain completes its progression: <strong>יְהוָה אֱלֹהִים צְבָאוֹת הֲשִׁיבֵנוּ</strong> (<em>yĕhwāh ʾĕlōhîm ṣĕbāʾôt hăshîbênû</em>, "Restore us, O LORD God of hosts!") — the fullest divine title: YHWH + ʾĕlōhîm + ṣĕbāʾôt. The refrain\'s three occurrences build: v3 = ʾĕlōhîm; v7 = ʾĕlōhîm ṣĕbāʾôt; v19 = YHWH ʾĕlōhîm ṣĕbāʾôt — escalating toward the full covenant name. <strong>הָאֵר פָּנֶיךָ וְנִוָּשֵׁעָה</strong> — the petition unchanged: restoration does not come through Israel\'s achievement but through the return of the divine face.</p>',
  },
  "81": {
    "1": '<p>Psalm 81 is a festal psalm set to the <em>gittît</em> tune (Ps 8; 84 — possibly from Gath or a harvest/winepress instrument). <strong>הַרְנִינוּ לֵאלֹהִים עוּזֵּנוּ</strong> (<em>harninû lêʾlōhîm ʿuzzênû</em>, "Sing aloud to God our strength!") — <em>rānan</em>: to ring out, to shout in joy (the piercing sound of festival exuberance). <em>ʿUzzênû</em>: "our strength" — the divine name replaced by an epithet of power (Ps 46:1). <strong>הָרִיעוּ לֵאלֹהֵי יַעֲקֹב</strong> (<em>hārîʿû lêʾlōhê yaʿăqōb</em>, "shout for joy to the God of Jacob!") — <em>rûaʿ</em> (hiphil: to raise a war-cry/shout of joy — the ambiguous root covers both). The God of Jacob (Gen 28:13-16) — the covenant made at Bethel with the wanderer who wrestled until blessing came.</p>',
    "2": '<p><strong>שְׂאוּ-זִמְרָה וּתְנוּ-תֹף</strong> (<em>śĕʾû-zimrāh ûtĕnû-tōp</em>, "raise a song, beat the tambourine!") — <em>tōp</em>: the hand-drum/tambourine (Miriam\'s instrument at the Exodus — Exod 15:20; the women greeting David — 1 Sam 18:6). <strong>כִּנּוֹר נָעִים עִם-נָבֶל</strong> (<em>kinnôr nāʿîm ʿim-nābel</em>, "the sweet lyre with the harp") — <em>kinnôr nāʿîm</em>: "pleasant/sweet lyre" (the same root as David\'s epithet <em>nĕʿîm zĕmirôt yiśrāʾêl</em> — "the sweet singer of Israel" — 2 Sam 23:1). The full instrumental ensemble assembled for the festival.</p>',
    "3": '<p><strong>תִּקְעוּ בַחֹדֶשׁ שׁוֹפָר בַּכֵּסֶה לְיוֹם חַגֵּנוּ</strong> (<em>tiqĕʿû baḥōdesh shôpār bakkesse lĕyôm ḥaggênû</em>, "blow the shofar at the new moon, at the full moon, on our feast day!") — <em>baḥōdesh</em>: at the new moon (the beginning of the month); <em>bakkesse</em>: at the fullness/covering (the full moon — the 15th of the month). The combination identifies either the Feast of Tabernacles (Tishri 1 = new moon; Tishri 15 = full moon) or the Passover cycle. The <em>shôpār</em> (ram\'s horn) is blown at both new moons (Num 10:10) and major festivals (Lev 23:24).</p>',
    "4": '<p><strong>כִּי חֹק לְיִשְׂרָאֵל הוּא מִשְׁפָּט לֵאלֹהֵי יַעֲקֹב</strong> (<em>kî ḥōq lĕyiśrāʾêl hûʾ mishpāṭ lêʾlōhê yaʿăqōb</em>, "for it is a statute for Israel, a rule given by the God of Jacob") — <em>ḥōq</em>: a fixed ordinance (the decrees of the sacred calendar — Lev 23). <em>Mishpāṭ</em>: a determined ruling. The two terms emphasize fixity (<em>ḥōq</em>) and authority (<em>mishpāṭ</em>): this feast is neither optional nor human invention but divinely inscribed in the covenant calendar.</p>',
    "5": '<p><strong>עֵדוּת בִּיהוֹסֵף שָׂמוֹ בְּצֵאתוֹ עַל-אֶרֶץ מִצְרָיִם</strong> (<em>ʿêdût bîhôsêp śāmô bĕṣêtô ʿal-ʾereṣ miṣrāyim</em>, "he established it as a decree in Joseph when he went out over the land of Egypt") — the pronoun in <em>bĕṣêtô</em> (when he went out) is grammatically ambiguous: it could refer to Joseph rising to power, to Israel departing Egypt at the Exodus, or to God going out against Egypt in judgment (Exod 11:4). All three readings are defensible. <strong>שְׂפַת לֹא-יָדַעְתִּי אֶשְׁמָע</strong> (<em>śĕpat lōʾ-yādaʿtî ʾeshmaʿ</em>, "I heard a voice I had not known") — the dramatic shift into first person: the Psalmist (or personified Israel) says "I hear a language I did not know." This marks the transition into the embedded divine speech that runs through v16.</p>',
    "6": '<p>Divine speech begins. <strong>הֲסִירוֹתִי מִסֵּבֶל שִׁכְמוֹ</strong> (<em>hăsîrôtî missibbel shikmô</em>, "I removed the burden from his shoulder") — <em>sibbel</em>: the burden-basket (Exod 1:11 — Israel forced to carry burdens in Egypt; Exod 2:11 — Moses "saw their burdens"). <em>Shikmo</em>: his shoulder (the load-bearing joint). <strong>כַּפָּיו מִדּוּד תַּעֲבֹרְנָה</strong> (<em>kappāyw middûd taʿăbōrnāh</em>, "his hands were freed from the basket") — <em>dûd</em>: a large pot/basket for carrying clay bricks. The Exodus liberation described in terms of physical release from forced labor — hands freed from the brick-basket grounds the festival command in lived memory.</p>',
    "7": '<p><strong>בַּצָּרָה קָרָאתָ וָאֲחַלְּצֶךָּ</strong> (<em>baṣṣārāh qārāʾtā wāʾăḥallĕṣekā</em>, "in your distress you called, and I rescued you!") — <em>ṣārāh</em>: the narrow/distressed situation (Ps 18:6). <em>Ḥālaṣ</em> (piel: to draw out, liberate — pulling from a tight place). <strong>אֶעֶנְךָ בְּסֵתֶר רַעַם</strong> (<em>ʾeʿenkā bĕsêter raʿam</em>, "I answered you from the secret/hidden place of thunder") — <em>sêter raʿam</em>: the dark storm-cloud from which YHWH spoke at Sinai (Exod 19:16-20; 20:18-21). <strong>אֶבְחָנְךָ עַל-מֵי מְרִיבָה סֶלָה</strong> (<em>ʾebḥānĕkā ʿal-mê mĕrîbāh selāh</em>, "I tested you at the waters of Meribah!") — Exod 17:7 and Num 20:13: where Israel tested God and God tested Israel (Ps 95:8-9). <em>Selāh</em>.</p>',
    "8": '<p><strong>שְׁמַע עַמִּי וְאָעִידָה בָּךְ</strong> (<em>shĕmaʿ ʿammî wĕʾāʿîdāh bāk</em>, "listen, O my people, while I admonish you!") — <em>ʿûd</em> (hiphil: to testify against, to warn, to admonish — as a covenant witness). The divine speech becomes a covenant lawsuit: God as the witness against Israel\'s faithlessness. <strong>יִשְׂרָאֵל אִם-תִּשְׁמַע-לִי</strong> (<em>yiśrāʾêl ʾim-tishmaʿ-lî</em>, "O Israel, if you would only listen to me!") — the conditional (Deut 28 pattern): what follows are covenant terms and their consequences, not mere exhortation.</p>',
    "9": '<p><strong>לֹא-יִהְיֶה בְךָ אֵל זָר</strong> (<em>lōʾ-yihyeh bĕkā ʾêl zār</em>, "there must be no foreign god among you!") — <em>ʾêl zār</em>: strange/foreign god (Deut 32:12). <strong>וְלֹא תִשְׁתַּחֲוֶה לְאֵל נֵכָר</strong> (<em>wĕlōʾ tishtaḥăweh lĕʾêl nêkār</em>, "you must not bow down to any alien god!") — <em>nêkār</em>: the foreign, alien (Ruth 2:10). Two words for foreignness (<em>zār</em> and <em>nêkār</em>) applied to idols — restating the First Commandment in different language.</p>',
    "10": '<p><strong>אָנֹכִי יְהוָה אֱלֹהֶיךָ הַמַּעַלְךָ מֵאֶרֶץ מִצְרָיִם</strong> (<em>ʾānōkî yĕhwāh ʾĕlōhêkā hammmaʿalkā mêʾereṣ miṣrāyim</em>, "I am the LORD your God, who brought you up out of the land of Egypt!") — verbatim citation of the Decalogue preamble (Exod 20:2; Deut 5:6). The divine speech in the psalm quotes itself — the God who established Sinai re-presents it in the festal setting. <strong>הַרְחֶב-פִּיךָ וַאֲמַלְאֵהוּ</strong> (<em>harḥeb-pîkā waʾămalʾêhû</em>, "open your mouth wide, and I will fill it!") — like a parent bird feeding nestlings who open their mouths wide to receive (Ps 104:27-28). The wide-open mouth is the posture of receptive dependence — contrasted with the people\'s actual behavior in v11.</p>',
    "11": '<p><strong>וְלֹא-שָׁמַע עַמִּי לְקוֹלִי</strong> (<em>wĕlōʾ-shāmaʿ ʿammî lĕqôlî</em>, "but my people did not listen to my voice") — the heartbreak of divine speech: the invitation of v10 refused by the very people addressed as "my people" (<em>ʿammî</em> — the covenant-ownership word). <em>Lōʾ-shāmaʿ</em>: the Shema inverted. <strong>וְיִשְׂרָאֵל לֹא-אָבָה לִי</strong> (<em>wĕyiśrāʾêl lōʾ-ʾābāh lî</em>, "Israel would not submit to me!") — <em>ʾābāh</em>: to be willing, to consent (Isa 1:19: "if you are willing and obedient, you shall eat the good of the land"). Israel\'s "not-willing" is the active rejection of the feast God offered.</p>',
    "12": '<p><strong>וָאֲשַׁלְּחֵהוּ בִּשְׁרִירוּת לִבָּם</strong> (<em>wāʾăshallĕḥêhû bishŏrîrût libbām</em>, "so I gave them over to their stubborn hearts") — <em>shālaḥ</em>: to send, to release, to let go (releasing them to their own trajectory). <em>Shĕrîrût lêb</em>: stubbornness/hardness of heart (Deut 29:18; Jer 3:17; 7:24). Paul\'s parallel in Rom 1:24: <em>παρέδωκεν αὐτοὺς ὁ θεός</em> ("God gave them over") — the same judicial action: abandonment-to-consequence as punishment for willful rejection. <strong>יֵלְכוּ בְּמוֹעֲצוֹתֵיהֶם</strong> (<em>yêlĕkû bĕmôʿăṣôtêhem</em>, "to follow their own devices") — <em>môʿēṣāh</em>: counsel, deliberate plan (from <em>yāʿaṣ</em>: to counsel). Stubbornness generates its own counsels; God\'s release is to let the self-generated counsel run its course.</p>',
    "13": '<p><strong>לוּ עַמִּי שֹׁמֵעַ לִי</strong> (<em>lû ʿammî shōmêaʿ lî</em>, "if only my people would listen to me!") — <em>lû</em>: the particle of unfulfilled wish (as in Num 14:2: "if only we had died in Egypt!" — the contrary-to-fact wishful). God expressing a divine wish that Israel had listened — genuine divine longing over uncollected faithfulness. <strong>יִשְׂרָאֵל בִּדְרָכַי יְהַלֵּכוּ</strong> (<em>yiśrāʾêl bîdrākhay yĕhallêkû</em>, "if only Israel would walk in my ways!") — <em>dĕrākhay</em>: my ways (the <em>halakah</em> — the walk-path of covenantal life). The divine lament over forfeited blessing.</p>',
    "14": '<p><strong>כִּמְעַט אוֹיְבֵיהֶם אַכְנִיעַ</strong> (<em>kimĕʿaṭ ʾôyĕbêhem ʾakhnîaʿ</em>, "I would quickly subdue their enemies!") — <em>kimĕʿaṭ</em>: "as a small thing, soon, quickly" — subduing enemies would be a small matter for God. <em>Kānaʿ</em> (hiphil: to bring low, to subdue — Josh 7:12-13; Judg 4:23). <strong>וְעַל-צָרֵיהֶם אָשִׁיב יָדִי</strong> (<em>wĕʿal-ṣārêhem ʾāshîb yādî</em>, "and turn my hand against their foes!") — <em>shûb yād</em>: to turn one\'s hand against — the divine hand employed against Israel\'s enemies instead of against Israel. The counterfactual: IF Israel listened → THEN enemies quickly subdued.</p>',
    "15": '<p><strong>מְשַׂנְאֵי יְהוָה יְכַחֲשׁוּ-לוֹ</strong> (<em>mĕśanʾê yĕhwāh yĕkhaḥăshû-lô</em>, "those who hate YHWH would cringe before him!") — <em>kāḥash</em> (piel: to cringe, to fawn in feigned submission — as a conquered party): the enemies who hated God would come crawling. <strong>וִיהִי עִתָּם לְעוֹלָם</strong> (<em>wîhî ʿittām lĕʿôlām</em>, "and Israel\'s time would have endured forever!") — <em>ʿittām</em>: their appointed time of blessing/wellbeing. The reward of obedience: Israel\'s peace fixed, not subject to the rise-and-fall cycles of the Judges.</p>',
    "16": '<p><strong>וַיַּאֲכִלֵהוּ מֵחֵלֶב חִטָּה</strong> (<em>wayyaʾăkhîlêhû mêḥêleb ḥiṭṭāh</em>, "I would have fed you with the finest of the wheat!") — <em>ḥêleb ḥiṭṭāh</em>: "the fat/richest of the wheat" (the very finest grain — <em>ḥêleb</em> is the word for the best portion offered in sacrifice: Lev 3:16-17). <strong>וּמִצּוּר דְּבַשׁ אַשְׂבִּיעֶךָ</strong> (<em>ûmiṣṣûr dĕbash ʾasbîʿekā</em>, "and with honey from the rock I would satisfy you!") — <em>dĕbash miṣṣûr</em>: honey from the rock (Deut 32:13 — wild honeybees nesting in rock clefts; the wilderness providing abundance in an unexpected place). The conditional feast: had Israel listened, the finest wheat and rock-honey would have been their portion — the wilderness provisions multiplied to their ultimate form.</p>',
  },
  "82": {
    "1": '<p>Psalm 82 is the most theologically concentrated psalm in the collection — the divine council under judgment. <strong>אֱלֹהִים נִצָּב בַּעֲדַת-אֵל בְּקֶרֶב אֱלֹהִים יִשְׁפֹּט</strong> (<em>ʾĕlōhîm niṣṣāb baʿădat-ʾêl bĕqereb ʾĕlōhîm yishpōṭ</em>, "God has taken his place in the divine assembly; in the midst of the gods he holds judgment!") — <em>niṣṣāb</em> (niphal of <em>nāṣab</em>: standing firmly, taking the presiding judge\'s position). <em>ʿĂdat-ʾêl</em>: the council/congregation of God (the divine council — the <em>bĕnê ʾĕlōhîm</em> of Gen 6:2; Job 1:6; 2:1; Ps 89:6-7: heavenly beings attending the divine sovereign). <em>Bĕqereb ʾĕlōhîm yishpōṭ</em>: "in the midst of the gods he holds court" — the participial <em>yishpōṭ</em> (ongoing characteristic judging). Whether the <em>ʾĕlōhîm</em> are human judges or divine beings is the central interpretive question: the death-like-Adam of v7 makes greater sense if addressed to beings who considered themselves immortal.</p>',
    "2": '<p><strong>עַד-מָתַי תִּשְׁפְּטוּ-עָוֶל</strong> (<em>ʿad-mātay tishpĕṭû-ʿāwel</em>, "how long will you go on judging unjustly?") — <em>ʿad-mātay</em>: the "how long" of lament, now in the divine mouth. <em>ʿāwel</em>: injustice, moral perversity (what is crooked). The divine council members who were meant to execute divine justice have done the opposite. <strong>וּפְנֵי רְשָׁעִים תִּשְׂאוּ-סֶלָה</strong> (<em>ûpĕnê rĕshāʿîm tiśʾû-selāh</em>, "showing partiality to the wicked! Selah.") — <em>nāśāʾ pānîm</em>: "to lift the face" (giving preferential treatment — the exact language Deut 10:17 uses for what God does NOT do: "who does not lift faces"). <em>Selāh</em>.</p>',
    "3": '<p><strong>שִׁפְטוּ-דַל וְיָתוֹם עָנִי וָרָשׁ הַצְדִּיקוּ</strong> (<em>shiptû-dal wĕyātôm ʿānî wārāsh haṣdîqû</em>, "defend the poor and fatherless; maintain the right of the afflicted and the destitute!") — four terms for the socially vulnerable: <em>dal</em> (the weak/economically depleted), <em>yātôm</em> (the orphan — without a father-protector), <em>ʿānî</em> (the afflicted), <em>rāsh</em> (the poor). <em>Haṣdîq</em> (hiphil: to declare righteous, to vindicate in court): the positive mandate — the council\'s job was to be advocates for the voiceless. This is the agenda of Isa 1:17; Mic 6:8; and the Sermon on the Mount (Matt 5:6).</p>',
    "4": '<p><strong>פַּלְּטוּ-דַל וְאֶבְיוֹן מִיַּד רְשָׁעִים הַצִּילוּ</strong> (<em>palĕṭû-dal wĕʾebyôn miyad rĕshāʿîm haṣṣîlû</em>, "rescue the poor and needy; save them from the grip of the wicked!") — <em>pālaṭ</em> (piel: to cause to escape, to rescue from the narrow place); <em>nāṣal</em> (hiphil: to snatch away to safety). Two rescue verbs paired with two victim terms. <em>Miyad rĕshāʿîm</em>: "from the hand of the wicked" — the hand as the instrument of power and oppression. This is the divine council\'s actual mandate: to liberate the powerless from the grip of the powerful.</p>',
    "5": '<p><strong>לֹא יָדְעוּ וְלֹא יָבִינוּ בַּחֲשֵׁכָה יִתְהַלָּכוּ</strong> (<em>lōʾ yādĕʿû wĕlōʾ yābînû baḥăshêkāh yithallākû</em>, "they have no knowledge and no understanding; they walk about in darkness!") — the triple failure: no knowledge (<em>lōʾ yādĕʿû</em>), no understanding (<em>lōʾ yābînû</em>), walking in darkness (<em>baḥăshêkāh</em>). The council-members who should dispense divine wisdom are themselves without wisdom and in darkness. <strong>יִמּוֹטוּ כָּל-מוֹסְדֵי אָרֶץ</strong> (<em>yimmôṭû kol-môsĕdê ʾāreṣ</em>, "all the foundations of the earth are shaken!") — <em>môsĕdîm</em>: foundations (Ps 18:15; Job 38:4). The moral failure of the heavenly council reverberates cosmically: when justice fails at the heavenly level, the earth\'s foundations themselves become unstable (Prov 2:21-22; Isa 24:18-19).</p>',
    "6": '<p><strong>אֲנִי-אָמַרְתִּי אֱלֹהִים אַתֶּם וּבְנֵי עֶלְיוֹן כֻּלְּכֶם</strong> (<em>ʾănî-ʾāmartî ʾĕlōhîm ʾattem ûbĕnê ʿelyôn kullĕkem</em>, "I declared, \'You are gods, sons of the Most High, every one of you!\'") — the divine "I" recalling a prior declaration: God himself conferred the status <em>ʾĕlōhîm</em> and <em>bĕnê ʿelyôn</em> (sons of the Most High) on the council-members. This is the foundation from which v7\'s reversal is so devastating. Jesus cites this verse in John 10:34-35: "Is it not written in your Law, \'I said, you are gods\'? If he called them gods to whom the word of God came — and Scripture cannot be broken — how can you say that the one the Father consecrated and sent into the world is blaspheming by saying \'I am God\'s Son\'?" The argument moves from the lesser to the greater: if the divine council received "gods," how much more the one God consecrated and sent.</p>',
    "7": '<p><strong>אָכֵן כְּאָדָם תְּמוּתוּן וּכְאַחַד הַשָּׂרִים תִּפֹּלוּ</strong> (<em>ʾāken kĕʾādām tĕmûtûn ûkĕʾaḥad haśśārîm tippōlû</em>, "nevertheless, you will die like the man [Adam]/like human beings, and fall like any fallen ruler!") — <em>ʾāken</em>: "nevertheless, however" — the adversative that shatters the status of v6. <em>Kĕʾādām</em>: "like Adam" or "like a human" — the polysemy is likely intentional: both readings operate simultaneously. To die like Adam is to share the curse of Gen 3:19 ("you are dust, and to dust you shall return") — the beings designated "gods" will share the fate of the one who grasped for divine status and received mortality instead. <em>Kĕʾaḥad haśśārîm tippōlû</em>: "like one of the rulers you will fall" — Isa 14:12-15 (the fall of the king of Babylon). The ultimate theodicy: the unjust divine council will be subject to death itself.</p>',
    "8": '<p><strong>קוּמָה אֱלֹהִים שָׁפְטָה הָאָרֶץ</strong> (<em>qûmāh ʾĕlōhîm shāpĕṭāh hāʾāreṣ</em>, "Rise up, O God, judge the earth!") — the Psalmist\'s voice returns for the first time since v1. <em>Qûm</em> (the warrior\'s arising — Ps 68:1: "let God arise, let his enemies be scattered"): the call for God to actively judge replaces the failed council. <strong>כִּי-אַתָּה תִנְחַל בְּכָל-הַגּוֹיִם</strong> (<em>kî-ʾattāh tinḥal bĕkhol-haggôyim</em>, "for all the nations belong to you!") — <em>nāḥal</em>: to inherit, to take possession. The psalm ends on a massive claim: not just Israel but all the nations are God\'s inheritance. The unjust sub-rulers replaced by the one just Sovereign who owns every nation — the universal scope resolves the crisis of the psalm.</p>',
  },
  "83": {
    "1": '<p>Psalm 83 is the final Asaph psalm and the longest. <strong>אֱלֹהִים אַל-דֳּמִי-לָךְ אַל-תֶּחֱרַשׁ וְאַל-תִּשְׁקֹט אֵל</strong> (<em>ʾĕlōhîm ʾal-dŏmî-lāk ʾal-teḥĕrash wĕʾal-tishqōṭ ʾêl</em>, "O God, do not remain silent; do not hold your peace or be still, O God!") — three synonymous verbs of divine inaction: <em>dāmam</em> (to be silent, to stand still); <em>ḥārash</em> (to be deaf/silent — Isa 42:14: a woman who has been quiet in labor); <em>shāqaṭ</em> (to be at rest, undisturbed — the tranquility of the uninvolved). The triple negation is the urgency of the lament: three different kinds of divine non-action are all pleaded against simultaneously.</p>',
    "2": '<p><strong>כִּי-הִנֵּה אוֹיְבֶיךָ יֶהֱמָיוּן</strong> (<em>kî-hinneh ʾôyĕbêkā yehĕmāyûn</em>, "For behold, your enemies are in an uproar!") — <em>hāmāh</em>: to roar, to be in tumult (used of the sea — Ps 46:3; 65:7 — and of roaring enemy nations — Ps 46:6). <strong>וּמְשַׂנְאֶיךָ נָשְׂאוּ רֹאשׁ</strong> (<em>ûmĕśanʾêkā nāśĕʾû rōʾsh</em>, "those who hate you have raised their heads!") — <em>nāśāʾ rōʾsh</em>: to lift the head (the gesture of arrogant self-assertion — Judg 8:28; Ps 110:7). The enemies are described as those who hate God — their opposition to Israel is opposition to the God of Israel.</p>',
    "3": '<p><strong>עַל-עַמְּךָ יַעֲרִימוּ סוֹד</strong> (<em>ʿal-ʿammĕkā yaʿărîmû sôd</em>, "they devise cunning plans against your people!") — <em>ʿāram</em> (hiphil: to be crafty, to devise schemes — the same root as the "shrewd/crafty" serpent of Gen 3:1). <em>Sôd</em>: a secret council (Jer 23:18 — the divine <em>sôd</em> in which the true prophet stands). The enemies have their own counter-<em>sôd</em> against God\'s people. <strong>וְיִתְיָעֲצוּ עַל-צְפוּנֶיךָ</strong> (<em>wĕyiṯyāʿăṣû ʿal-ṣĕpûnêkā</em>, "and scheme against your treasured ones!") — <em>ṣĕpûnîm</em>: the hidden/treasured ones (from <em>ṣāpan</em>: to hide, to treasure — Col 3:3: "your life is hidden with Christ in God").</p>',
    "4": '<p><strong>אָמְרוּ לְכוּ וְנַכְחִידֵם מִגּוֹי</strong> (<em>ʾāmĕrû lĕkû wĕnakhḥîdêm miggôy</em>, "they say, \'Come, let us wipe them out as a nation!\'") — <em>kāḥad</em> (hiphil: to destroy completely, to annihilate — to cause to cease to exist). The genocidal intention: to remove Israel from the category of <em>gôy</em> (nation). <strong>וְלֹא-יִזָּכֵר שֵׁם-יִשְׂרָאֵל עוֹד</strong> (<em>wĕlōʾ-yizzākêr shêm-yiśrāʾêl ʿôd</em>, "let the name of Israel be remembered no more!") — <em>zākar</em> (niphal: to be remembered). The goal: not merely military defeat but complete obliteration of memory — the erasure of Israel\'s name from human consciousness.</p>',
    "5": '<p><strong>כִּי נוֹעֲצוּ לֵב יַחְדָּו</strong> (<em>kî nôʿăṣû lêb yaḥdāw</em>, "for they conspire together with one accord!") — <em>yāʿaṣ</em>: to counsel, to scheme. <em>Yaḥdāw</em>: together, in unified concert. What the Shema calls Israel to do toward God (to love with the whole heart), the nations are doing against him. <strong>עָלֶיךָ בְּרִית יִכְרֹתוּ</strong> (<em>ʿālêkā bĕrît yikrōtû</em>, "they have made a covenant against you!") — <em>kārat bĕrît</em>: to cut a covenant (the standard treaty formula). The nations have made a formal alliance directed against God himself — Ps 2:2: the kings of the earth conspiring against YHWH and his Anointed.</p>',
    "6": '<p><strong>אָהֳלֵי אֱדוֹם וְיִשְׁמְעֵאלִים מוֹאָב וְהַגְרִים</strong> (<em>ʾōhŏlê ʾĕdôm wĕyishmaʿêlîm môʾāb wĕhagrîm</em>, "the tents of Edom and the Ishmaelites, Moab and the Hagrites") — the first four of a 10-nation coalition. Edom (descended from Esau — Israel\'s twin, carrying the deepest fratricidal betrayal: Obad 10-14; Ps 137:7); Ishmaelites (descendants of Ishmael — the traders who carried Joseph to Egypt — Gen 37:25); Moab (east of the Dead Sea — descended from Lot, fighting Israel from Balak onward — Num 22-24); Hagrites (descendants of Hagar — northern Arabian tribe: 1 Chr 5:10,19-20). Each carries a genealogical relationship with Israel making the betrayal doubly bitter.</p>',
    "7": '<p><strong>גְּבַל וְעַמּוֹן וַעֲמָלֵק פְּלֶשֶׁת עִם-יֹשְׁבֵי צוֹר</strong> (<em>gĕbal wĕʿammôn waʿămālêq pĕleshet ʿim-yōshĕbê ṣôr</em>, "Gebal and Ammon and Amalek, Philistia with the inhabitants of Tyre!") — Gebal (Phoenician Byblos, or Edomite Gebalene); Ammon (east of the Jordan, descended from Lot — Judg 10-11; 2 Sam 10); Amalek (the perpetual wilderness enemy — Exod 17:8-16; Deut 25:17-19); Philistia (the coastal confederation — primary antagonist in Judges-Samuel); Tyre (the great Phoenician trading city — Ezek 26-28). The geographic sweep covers east, south, north, and west.</p>',
    "8": '<p><strong>גַּם-אַשּׁוּר נִלְוָה עִמָּם</strong> (<em>gam-ʾashshûr nilwāh ʿimmām</em>, "Assyria too has joined them!") — <em>lāwāh</em> (niphal: to join oneself, to attach — the same root as Levi\'s name). Assyria\'s attachment would date the setting to the 8th-7th centuries BCE when Assyria dominated the region. <strong>הָיוּ זְרוֹעַ לִבְנֵי-לוֹט סֶלָה</strong> (<em>hāyû zĕrôaʿ libnê-lôṭ selāh</em>, "they lend their strength to the children of Lot!") — <em>zĕrôaʿ</em>: the arm/strength (Ps 77:15; Isa 52:10). Assyria\'s massive military arm strengthening the smaller regional powers. The children of Lot (Moab and Ammon — v6) endorsed by the ancient Near East\'s superpower. <em>Selāh</em> marks completion of the 10-nation inventory.</p>',
    "9": '<p><strong>עֲשֵׂה-לָהֶם כְּמִדְיָן כְּסִיסְרָא כְיָבִין בְּנַחַל קִישׁוֹן</strong> (<em>ʿăśêh-lāhem kĕmidyān kĕsîsĕrāʾ kĕyābîn bĕnaḥal qîshôn</em>, "Do to them as you did to Midian, as to Sisera and Jabin at the river Kishon!") — three historical precedents: Midian (the defeat of 135,000 enemy soldiers under Gideon — Judg 7-8; divine intervention that turned the enemies against each other); Sisera (the Canaanite general whose army was overwhelmed at the Kishon in the rain — Judg 4-5); Jabin (the king of Hazor behind Sisera — Judg 4:2). The Kishon — a wadi near Megiddo, Judg 5:21: "the torrent Kishon swept them away." Three situations where God alone won the battle are the template for the present petition.</p>',
    "10": '<p><strong>נִשְׁמְדוּ בְעֵין-דֹּאר</strong> (<em>nishĕmĕdû bĕʿên-dōʾr</em>, "they were destroyed at En-dor!") — <em>shāmad</em> (niphal: to be annihilated). En-dor: near the Jezreel valley at the foot of Mount Moreh, near Gideon\'s battlefield (not the En-dor of the witch — 1 Sam 28:7). <strong>הָיוּ דֹמֶן לָאֲדָמָה</strong> (<em>hāyû dōmen lāʾădāmāh</em>, "they became dung for the ground!") — <em>dōmen</em>: dung, manure (Jer 8:2; 9:22 — "they shall be like dung on the surface of the ground"). The bodies of the powerful coalition become fertilizer — the ultimate reversal of their ambition to wipe Israel from the earth.</p>',
    "11": '<p><strong>שִׁיתֵמוֹ נְדִיבֵימוֹ כְּעֹרֵב וְכִזְאֵב</strong> (<em>shîtêmô nĕdîbêmô kĕʿōrêb wĕkhizʾêb</em>, "make their nobles like Oreb and Zeeb!") — Oreb (Raven) and Zeeb (Wolf): the two princes of Midian captured and executed by the Ephraimites at the Jordan during Gideon\'s pursuit — Judg 7:25 ("they killed Oreb at the rock of Oreb, and Zeeb at the wine press of Zeeb"). <strong>וְכִזְבַח וּכְצַלְמֻנָּע כָּל-נְסִיכֵימוֹ</strong> (<em>wĕkhizbaḥ ûkĕṣalmunnāʿ kol-nĕsîkêmô</em>, "and all their princes like Zebah and Zalmunna!") — the two kings of Midian whom Gideon personally executed as blood-avengers for his brothers — Judg 8:5-21. All four Midianite leaders are paradigms of God\'s power to eliminate the most dangerous enemies.</p>',
    "12": '<p><strong>אֲשֶׁר אָמְרוּ נִירְשָׁה לָּנוּ אֵת נְאוֹת אֱלֹהִים</strong> (<em>ʾăsher ʾāmĕrû nîrĕshāh llānû ʾêt nĕʾôt ʾĕlōhîm</em>, "who said, \'Let us seize for ourselves the pastures of God!\'") — <em>nāʾāh</em>: pastureland, the pleasant meadows (Ps 23:2: "green pastures"). <em>Nîrĕshāh</em>: we will inherit/possess (from <em>yārash</em>: the covenantal inheritance term). The coalition\'s specific goal: not just to defeat Israel but to take possession of the land promised to Abraham. God\'s land claimed by those who reject his covenant (Lev 25:23: "the land is mine").</p>',
    "13": '<p><strong>אֱלֹהַי שִׁיתֵמוֹ כַגַּלְגַּל כְּקַשׁ לִפְנֵי-רוּחַ</strong> (<em>ʾĕlōhay shîtêmô khagalgal kĕqash lipnê-rûaḥ</em>, "O my God, make them like whirling dust, like chaff before the wind!") — <em>galgal</em>: a wheel, something rolling — specifically the round, hollow-stemmed tumbleweed that breaks off at the root in autumn and rolls across the landscape driven by wind (Isa 17:13: "like rolling things before the wind"; Job 21:18). <em>Qash</em>: dry straw/chaff (the winnowed lightweight residue — Ps 1:4; Isa 40:24). The coalition that threatened permanent erasure of Israel is itself to be erased without trace.</p>',
    "14": '<p><strong>כְּאֵשׁ תִּבְעַר-יָעַר וּכְלַהֲבָה תְּלַהֵט הָרִים</strong> (<em>kĕʾêsh tibʿar-yāʿar ûkĕlahăbāh tĕlahêṭ hārîm</em>, "as fire consumes the forest, as the flame sets the mountains ablaze!") — two fire images for thoroughness: <em>bāʿar</em> (to burn/consume — the complete combustion that does not stop until everything combustible is gone); <em>lāhaṭ</em> (piel: to flame fiercely, to scorch — the setting-ablaze of the mountains). The fire imagery prepares for v15\'s petition: "pursue them with your storm and terrify them with your tempest."</p>',
    "15": '<p><strong>כֵּן תִּרְדְּפֵם בְּסַעֲרֶךָ</strong> (<em>kên tirdĕpêm bĕsaʿărekā</em>, "so pursue them with your storm!") — <em>sāʿar</em>: the violent storm-wind (the whirlwind that took Elijah — 2 Kgs 2:1; YHWH\'s answer to Job — Job 38:1). <strong>וּבְסוּפָתְךָ תְבַהֲלֵם</strong> (<em>ûbĕsûpātĕkā tĕbahălêm</em>, "and terrify them with your tempest!") — <em>sûpāh</em>: a tornado (Prov 1:27; Isa 17:13). <em>Bāhal</em> (piel: to terrify, to throw into sudden panic — Josh 10:10; 1 Sam 7:10). The petition connects to Sisera\'s precedent: the Kishon river storm panicked his chariots (Judg 5:20-21: "the stars fought from heaven... against Sisera").</p>',
    "16": '<p><strong>מַלֵּא פְנֵיהֶם קָלוֹן</strong> (<em>mallêʾ pĕnêhem qālôn</em>, "fill their faces with shame!") — <em>qālôn</em>: dishonor, disgrace (the public opposite of <em>kābôd</em>/glory — Prov 3:35). <strong>וִיבַקְשׁוּ שִׁמְךָ יְהוָה</strong> (<em>wîbaqshû shimĕkā yĕhwāh</em>, "that they may seek your name, O LORD!") — the pivotal purpose clause: the shame of v16 has a redemptive goal. The enemies are shamed so that they will seek the divine name. <em>Bāqash shêm</em>: to seek the name (acknowledging and pursuing the God who has acted — Isa 55:6: "seek the LORD while he may be found"). The imprecation has a missionary ambition: judgment as the path to the enemies\' conversion.</p>',
    "17": '<p><strong>יֵבֹשׁוּ וְיִבָּהֲלוּ עֲדֵי-עַד</strong> (<em>yēbōshû wĕyibbāhălû ʿădê-ʿad</em>, "let them be put to shame and dismayed forever!") — <em>bôsh</em>: to be put to shame; <em>bāhal</em> (niphal: to be terrified, thrown into disarray). <em>ʿĂdê-ʿad</em>: "forever, unto eternity" — the temporal absolute for those who do not repent. <strong>וְיַחְפְּרוּ וְיֹאבֵדוּ</strong> (<em>wĕyaḥpĕrû wĕyōʾbêdû</em>, "let them be disgraced and perish!") — <em>ḥāpar</em>: to be confounded (to dig/scratch in the dust in humiliation); <em>ʾābed</em>: to perish. This verse covers those who refuse the redemptive shame of vv16,18 — the two tracks: shame-leading-to-seeking or shame-leading-to-perishing.</p>',
    "18": '<p><strong>וְיֵדְעוּ כִּי-אַתָּה שִׁמְךָ יְהוָה לְבַדֶּךָ עֶלְיוֹן עַל-כָּל-הָאָרֶץ</strong> (<em>wĕyêdĕʿû kî-ʾattāh shimĕkā yĕhwāh lĕbaddĕkā ʿelyôn ʿal-kol-hāʾāreṣ</em>, "let them know that you alone, whose name is the LORD, are the Most High over all the earth!") — the goal of the entire imprecatory psalm: not Israel\'s vengeance but universal knowledge (<em>yādaʿ</em>) of who YHWH is. <em>Lĕbaddĕkā</em>: "you alone" (Deut 32:12). <em>ʿElyôn</em>: the Most High (Gen 14:18-22; Dan 7:18,22). The psalm that began with the coalition plotting to erase Israel\'s name ends with the petition that the nations know the divine name — the eschatological reversal of Ps 2: conspiracy against God ends in the nations\' recognition of his sovereignty.</p>',
  },
  "84": {
    "1": '<p>Psalm 84 is one of the finest poems in the entire Psalter — a pilgrim\'s psalm from the sons of Korah, set to the <em>gittît</em> melody (Ps 8; 81). <strong>מַה-יְּדִידוֹת מִשְׁכְּנוֹתֶיךָ יְהוָה צְבָאוֹת</strong> (<em>mah-yĕdîdôt mishkĕnôtêkā yĕhwāh ṣĕbāʾôt</em>, "How lovely are your dwelling places, O LORD of hosts!") — <em>yĕdîdôt</em>: loveliness, belovedness (the plural abstract noun from <em>yādîd</em>: beloved/lovely — the same root related to love/affection). <em>Mishkĕnôtêkā</em>: your dwelling places (plural of the <em>mishkān</em> — the Tabernacle/Dwelling: Num 24:5). The exclamatory <em>mah</em> (how!) frames the opening as a cry of wonder, not a description. The Psalmist has not yet arrived — still on the road, burning with longing for a place he loves more than anywhere on earth.</p>',
    "2": '<p><strong>נִכְסְפָה וְגַם-כָּלְתָה נַפְשִׁי לְחַצְרוֹת יְהוָה</strong> (<em>niksĕpāh wĕgam-kāltāh napshî lĕḥaṣrôt yĕhwāh</em>, "my soul longs, yes, faints for the courts of the LORD!") — two verbs of extreme desire: <em>kāsap</em> (niphal: to pale/grow pale with longing — the whitening of intense desire: Gen 31:30: "you longed intensely for your father\'s house"); <em>kālāh</em> (to be consumed, to fail — Ps 119:81: "my soul <em>kāltāh</em> for your salvation"). The soul is consumed with longing until it fails. <strong>לִבִּי וּבְשָׂרִי יְרַנְּנוּ אֶל-אֵל חָי</strong> (<em>libbî ûbĕśārî yĕrannĕnû ʾel-ʾêl ḥāy</em>, "my heart and my flesh cry out for the living God!") — the whole person (heart = inner; flesh = body) crying simultaneously. <em>ʾÊl ḥāy</em>: the living God (Ps 42:2; 2 Kgs 19:4,16).</p>',
    "3": '<p><strong>גַּם-צִפּוֹר מָצְאָה בַיִת וּדְרוֹר קֵן לָהּ</strong> (<em>gam-ṣippôr māṣĕʾāh bayit ûdĕrôr qên lāh</em>, "even the sparrow has found a home, and the swallow a nest for herself!") — <em>ṣippôr</em>: small bird/sparrow (the most ordinary, inexpensive bird — Matt 10:29: "are not two sparrows sold for a penny?"); <em>dĕrôr</em>: the swallow or swift (a migratory bird that travels thousands of miles). Both birds have found their home; the Psalmist is still on the pilgrim road. The irony is tender and painful: the least of birds nests in the sanctuary; the Psalmist who loves it most cannot yet be there. <strong>אֲשֶׁר-שָׁתָה אֶפְרֹחֶיהָ אֶת-מִזְבְּחוֹתֶיךָ</strong> (<em>ʾăsher-shātāh ʾephrōḥêhā ʾet-mizbĕḥôtêkā</em>, "where she may lay her young — even your altars, O LORD of hosts, my King and my God!") — the bird nests at the very altars: the holiest point of the sanctuary. The contrast between the bird\'s effortless belonging and the Psalmist\'s aching distance is the psalm\'s central tension.</p>',
    "4": '<p><strong>אַשְׁרֵי יוֹשְׁבֵי בֵיתֶךָ עוֹד יְהַלְלוּךָ סֶּלָה</strong> (<em>ʾashrê yôshĕbê bêtekā ʿôd yĕhallĕlûkā selāh</em>, "Blessed are those who dwell in your house; they are ever singing your praise! Selah.") — the first of three <em>ʾashrê</em> beatitudes in Psalm 84 (vv4, 5, 12). <em>ʾAshĕrê</em>: "how blessed!" — the plural of <em>ʾōsher</em> (blessing/happiness). The Levites and priests who lived in the temple courts: <em>yôshĕbê bêtekā</em> (those who dwell in the house). They are ever (<em>ʿôd</em>: still, continuously) praising. The Psalmist on the road looks at permanent residents and pronounces them blessed. The beatitude structure sets up the psalm\'s progress: dwellers (v4), pilgrims (v5), trusters (v12). <em>Selāh</em>.</p>',
    "5": '<p><strong>אַשְׁרֵי אָדָם עוֹז-לוֹ בָךְ מְסִלּוֹת בִּלְבָבָם</strong> (<em>ʾashrê ʾādām ʿōz-lô bāk mĕsillôt bibbābām</em>, "Blessed is the man whose strength is in you, in whose heart are the pilgrim roads!") — the second <em>ʾashrê</em>: not the temple-resident but the active pilgrim. <em>ʿŌz lô bāk</em>: whose strength is in you (Ps 46:1 — not in his own stamina). <em>Mĕsillôt bibbābām</em>: "pilgrimage roads are in their heart" — <em>mĕsillāh</em>: a raised highway (Isa 40:3: "prepare the way of the LORD, make straight a highway"). The roads exist first in the interior: the longing for Zion creates the pilgrimage. The Psalms of Ascent (120-134) are the liturgical expression of those interior roads.</p>',
    "6": '<p><strong>עֹבְרֵי בְּעֵמֶק הַבָּכָא מַעְיָן יְשִׁיתוּהוּ</strong> (<em>ʿōbĕrê bĕʿêmeq habbākhāʾ maʿyān yĕshîtûhû</em>, "as they pass through the valley of Baka, they make it a place of springs!") — <em>ʿêmeq habbākhāʾ</em>: the "valley of Baka" — <em>bākhāʾ</em> may refer to a balsam/mastic tree (2 Sam 5:23-24; the trees in whose rustle David heard God\'s movement) or be related to <em>bākāh</em> (to weep) — "the valley of weeping/tears." Both readings are defensible. The transformation: they <em>make</em> it a spring — <em>yāshat</em>: to establish. The weeping valley becomes a spring by the pilgrims\' passing through. <strong>גַּם-בְּרָכוֹת יַעְטֶה מוֹרֶה</strong> (<em>gam-bĕrākhôt yaʿṭeh môreh</em>, "the early rain also covers it with pools!") — <em>môreh</em>: the early October-November rain (Joel 2:23).</p>',
    "7": '<p><strong>יֵלְכוּ מֵחַיִל אֶל-חָיִל</strong> (<em>yêlĕkû mêḥayil ʾel-ḥāyil</em>, "they go from strength to strength!") — <em>ḥayil</em>: strength, valor (Ruth 2:1; 3:11: "a woman of valor"). From <em>ḥayil</em> to <em>ḥayil</em>: each stage of the pilgrimage depletes and then replenishes — the pilgrim does not weaken but strengthens with each day toward Zion. The movement is paradoxical: the difficult valley (v6) produces not weakness but deeper resources. <strong>יֵרָאֶה אֶל-אֱלֹהִים בְּצִיּוֹן</strong> (<em>yērāʾeh ʾel-ʾĕlōhîm bĕṣiyyôn</em>, "each one appears before God in Zion!") — <em>rāʾāh</em> (niphal: the cultic term for appearing before the divine presence — Exod 34:23: "three times a year all your males shall appear before the LORD").</p>',
    "8": '<p><strong>יְהוָה אֱלֹהִים צְבָאוֹת שִׁמְעָה תְפִלָּתִי</strong> (<em>yĕhwāh ʾĕlōhîm ṣĕbāʾôt shimmĕʿāh tĕpillātî</em>, "O LORD God of hosts, hear my prayer!") — the fullest possible divine title (YHWH + ʾĕlōhîm + ṣĕbāʾôt — as in Ps 80:19): invoked as the pilgrim makes his mid-journey petition. <strong>הַאֲזִינָה אֱלֹהֵי יַעֲקֹב סֶלָה</strong> (<em>hāʾăzînāh ʾĕlōhê yaʿăqōb selāh</em>, "give ear, O God of Jacob!") — Jacob who walked the roads from Beersheba to Haran and from Haran to Peniel — the pilgrim-patriarch is the guarantor of God\'s ear for traveling worshipers. <em>Selāh</em>.</p>',
    "9": '<p><strong>רְאֵה אֱלֹהִים מָגִנֵּנוּ</strong> (<em>rĕʾêh ʾĕlōhîm māginnênû</em>, "Behold our shield, O God!") — <em>māgên</em>: shield (the divine covering — Gen 15:1: "I am your shield"; Ps 3:3; 18:2). <strong>וְהַבֵּט פְּנֵי מְשִׁיחֶךָ</strong> (<em>wĕhabbêṭ pĕnê mĕshîḥekā</em>, "look on the face of your anointed!") — <em>mĕshîaḥ</em>: anointed one (the Messiah — the anointed king consecrated by oil: 1 Sam 16:13; 2 Sam 22:51; Ps 2:2; 132:10). Since the whole people is making pilgrimage to appear before God (v7), the prayer for the king is the prayer for the nation\'s representative. The divine looking at the anointed one\'s face is the counterpart to the divine face shining on Israel (Ps 80:3,7,19).</p>',
    "10": '<p><strong>כִּי טוֹב-יוֹם בַּחֲצֵרֶיךָ מֵאָלֶף</strong> (<em>kî ṭôb-yôm baḥăṣêrêkā mêʾālep</em>, "for a single day in your courts is better than a thousand elsewhere!") — the comparison is superlative: not "better than a thousand bad days" but "better than a thousand days anywhere else." The arithmetic of divine presence upends all human calculation. <strong>בָּחַרְתִּי הִסְתּוֹפֵף בְּבֵית אֱלֹהַי</strong> (<em>bāḥartî histôpêp bĕbêt ʾĕlōhay</em>, "I would rather stand at the threshold of the house of my God!") — <em>histôpêp</em>: to stand at the threshold, to be a doorkeeper (from <em>sap</em>: threshold/sill). The lowest status role in the sanctuary — simply standing at the door — preferred to comfort in the wicked\'s tents. <strong>מִדּוּר בְּאָהֳלֵי-רֶשַׁע</strong> (<em>middûr bĕʾōhŏlê-reshaʿ</em>, "than dwell comfortably in the tents of the wicked!") — even the permanent residence of the wicked cannot compete with the lowest post at the divine door.</p>',
    "11": '<p><strong>כִּי שֶׁמֶשׁ וּמָגֵן יְהוָה אֱלֹהִים</strong> (<em>kî shemesh ûmāgên yĕhwāh ʾĕlōhîm</em>, "for the LORD God is a sun and shield!") — <em>shemesh</em> (sun) is a rare divine epithet — God is more commonly likened to light, fire, and glory than to the sun itself (the solar disk was a pagan worship object: Ezek 8:16 — men with their backs to the temple worshipping the sun). The epithet is deliberately adopted against this background: the sun-worshippers\' object of veneration is, in fact, YHWH\'s function — warmth, light, orientation, life. The pairing with <em>māgên</em> (shield) covers both positive provision (light/warmth) and protective covering. <strong>לֹא יִמְנַע-טוֹב לַהֹלְכִים בְּתָמִים</strong> (<em>lōʾ yimnaʿ-ṭôb lahōlĕkhîm bĕtāmîm</em>, "no good thing does he withhold from those who walk with integrity!") — <em>tāmîm</em>: wholeness, blamelessness (from <em>tāmam</em>: to be complete — the walk not split between YHWH and idols).</p>',
    "12": '<p><strong>יְהוָה צְבָאוֹת אַשְׁרֵי אָדָם בֹּטֵחַ בָּךְ</strong> (<em>yĕhwāh ṣĕbāʾôt ʾashrê ʾādām bōṭêaḥ bāk</em>, "O LORD of hosts, blessed is the one who trusts in you!") — the third and climactic <em>ʾashrê</em> beatitude of the psalm. The progression: v4 blessed are the dwellers (in the presence); v5 blessed is the pilgrim (on the way); v12 blessed is the truster (anywhere). The third beatitude is the most expansive: any <em>ʾādām</em> (any person) whose posture is trust (<em>bāṭaḥ</em>: to lean upon, to place one\'s weight on — Ps 22:4-5; Prov 3:5). The psalm that began with extraordinary longing for the place of God\'s presence ends by locating blessing in the relationship of trust — a move from physical presence to interior posture.</p>',
  },
  "85": {
    "1": '<p>Psalm 85, a Korah psalm, moves between recollection of past restoration and petition for present renewal. <strong>רָצִיתָ יְהוָה אַרְצֶךָ שַׁבְתָּ שְׁבִית יַעֲקֹב</strong> (<em>rāṣîtā yĕhwāh ʾarṣekā shab̈tā shĕbît yaʿăqōb</em>, "O LORD, you showed favor to your land; you restored the fortunes of Jacob!") — <em>rāṣāh</em>: to be pleased with, to accept favorably (Day of Atonement language — Lev 1:4; Isa 40:2: "her iniquity is pardoned"). <em>Shab̈tā shĕbît</em>: the cognate accusative — "you restored the restoration of Jacob" (idiom for returning from captivity — Deut 30:3; Jer 30:3; Job 42:10). The psalm\'s first three verses all use completed-action perfects — describing divine acts as done, laying them as the foundation for petition.</p>',
    "2": '<p><strong>נָשָׂאתָ עֲוֹן עַמֶּךָ כִּסִּיתָ כָל-חַטָּאתָם סֶלָה</strong> (<em>nāśāʾtā ʿăwōn ʿammekā kissîtā kol-ḥaṭṭāʾtām selāh</em>, "you forgave the iniquity of your people; you covered over all their sin! Selah.") — two paired verbs: <em>nāśāʾ ʿāwōn</em>: "to lift/bear iniquity" (as the scapegoat bears Israel\'s sins — Lev 16:22; as the Servant of Isa 53:12 "bore the sin of many"). <em>Kissāh ḥaṭṭāʾāh</em>: "to cover sin" (Ps 32:1: "blessed is the one whose sin is covered!" — Rom 4:7 cites Ps 32:1 directly). The two great acts of atonement: lifting and covering — both perfect-tense completed divine acts. <em>Selāh</em>.</p>',
    "3": '<p><strong>אָסַפְתָּ כָל-עֶבְרָתֶךָ הֱשִׁיבוֹתָ מֵחֲרוֹן אַפֶּךָ</strong> (<em>ʾāsaptā kol-ʿebrātekā hĕshîbôtā mêḥărôn ʾappekā</em>, "you withdrew all your wrath; you turned away from your fierce anger!") — <em>ʿebrāh</em>: overflow of wrath (the noun from <em>ʿābar</em>: to overflow); <em>ḥărôn ʾap</em>: the burning of the nostrils (Exod 32:12). Both were gathered in (<em>ʾāsap</em>: to collect, withdraw) and turned back. This third completed-action verse is the memory that makes petition in vv4-7 possible: God who has done all this can do it again.</p>',
    "4": '<p><strong>שׁוּבֵנוּ אֱלֹהֵי יִשְׁעֵנוּ</strong> (<em>shûbênû ʾĕlōhê yishʿênû</em>, "restore us again, O God of our salvation!") — the first petition: qal imperative of <em>shûb</em>: "cause us to return/restore us." The same verb that described Israel\'s physical return (<em>shab̈tā shĕbît</em> — v1) now turned back to God: cause the inner and national restoration that the physical return did not fully achieve. <em>ʾĔlōhê yishʿênû</em>: "God of our salvation" — the divine title that stakes the petition on God\'s own character as savior. <strong>וְהָפֵר כַּעַסְךָ עִמָּנוּ</strong> (<em>wĕhāpêr kaʿăśekā ʿimmānû</em>, "and set aside your displeasure against us!") — <em>pārar</em> (hiphil: to break, to annul, to cause to cease — used of breaking a covenant or decree).</p>',
    "5": '<p><strong>הַלְעוֹלָם תֶּאֱנַף-בָּנוּ</strong> (<em>halĕʿôlām teʾĕnap-bānû</em>, "will you be angry with us forever?") — <em>ʾānap</em>: to be angry (Deut 1:37; 4:21; 9:20). The interrogative <em>hal</em> (surely not?) expects a negative answer. <strong>תִּמְשֹׁךְ אַפְּךָ לְדֹר וָדֹר</strong> (<em>timmĕshōk ʾappĕkā lĕdōr wādōr</em>, "will you extend your anger through every generation?") — <em>māshak</em>: to draw out, to prolong (to pull something along — as water drawn from a well). Anger drawn through generations contrasts with Exod 34:6 (the divine character: "slow to anger" — <em>ʾerek ʾappayim</em>, literally "long-nostriled"). The petition presses the divine character against the present divine anger.</p>',
    "6": '<p><strong>הֲלֹא-אַתָּה תָּשׁוּב תְּחַיֵּנוּ</strong> (<em>hălōʾ-ʾattāh tāshûb tĕḥayyênû</em>, "will you not revive us again, so that your people may rejoice in you?") — the interrogative-expectant: <em>hălōʾ ʾattāh</em> presses the divine identity as the one who revives. <em>Ḥāyāh</em> (piel: to give life, to revive — 2 Kgs 13:21: the dead man touching Elisha\'s bones "revived and stood"; Hos 6:2: "on the third day he will raise us up"). <em>Tĕḥayyênû</em>: "revive us" — the resurrection language used for national renewal and, in the prophets, for eschatological resurrection. <strong>וְעַמְּךָ יִשְׂמְחוּ-בָךְ</strong> (<em>wĕʿammĕkā yiśmĕḥû-bāk</em>, "that your people may rejoice in you!") — joy in God as the fruit of revival: the returning life expresses itself in rejoicing in the divine person, not merely in changed circumstances.</p>',
    "7": '<p><strong>הַרְאֵנוּ יְהוָה חַסְדֶּךָ וְיֶשְׁעֲךָ תִּתֶּן-לָנוּ</strong> (<em>harʾênû yĕhwāh ḥasdekā wĕyeshʿăkā titten-lānû</em>, "Show us your steadfast love, O LORD, and grant us your salvation!") — <em>rāʾāh</em> (hiphil: to show, cause to see — to make the divine <em>ḥesed</em> visible and demonstrable). <em>Ḥasdekā</em>: your steadfast love (Lam 3:22). <em>Yeshʿăkā</em>: your salvation (the noun from <em>yāshaʿ</em>: to save — as in the name Jesus/Yeshua). The paired petition: make the love visible + give the salvation. The two are inseparable: showing the <em>ḥesed</em> and giving salvation are the same divine action.</p>',
    "8": '<p><strong>אֶשְׁמְעָה מַּה-יְדַבֵּר הָאֵל יְהוָה</strong> (<em>ʾeshĕmĕʿāh mah-yĕdabbêr hāʾêl yĕhwāh</em>, "I will listen to what God the LORD says!") — a dramatic turn: the Psalmist falls silent from his petitions and adopts the prophetic listening posture. <em>ʾEshĕmĕʿāh</em> (cohortative: I will listen — the deliberate act of oriented attention): as Samuel (1 Sam 3:9-10: "speak, for your servant is listening"), as Habakkuk (Hab 2:1: "I will stand at my watchpost and listen"). <strong>כִּי-יְדַבֵּר שָׁלוֹם אֶל-עַמּוֹ וְאֶל-חֲסִידָיו</strong> (<em>kî-yĕdabbêr shālôm ʾel-ʿammô wĕʾel-ḥăsîdāyw</em>, "for he will speak peace to his people and to his faithful ones!") — <em>shālôm</em>: comprehensive wholeness, covenant-restoration (Isa 52:7: "how beautiful... \'Your God reigns\'"). <strong>וְאַל-יָשׁוּבוּ לְכִסְלָה</strong> (<em>wĕʾal-yāshûbû lĕkhislāh</em>, "only let them not return to folly!") — <em>kĕsîlāh</em>: folly (from <em>kĕsîl</em>: the fool who refuses wisdom — Prov 1:32; 3:35). The peace is conditional: do not return to the foolishness of idolatry and covenant-breaking.</p>',
    "9": '<p><strong>אַךְ-קָרוֹב לִירֵאָיו יִשְׁעוֹ</strong> (<em>ʾak-qārôb lîrêʾāyw yishʿô</em>, "surely his salvation is near to those who fear him!") — <em>qārôb</em>: near, close (the divine salvation described as spatially imminent — Ps 34:7). <strong>לִשְׁכֹּן כָּבוֹד בְּאַרְצֵנוּ</strong> (<em>lishkōn kābôd bĕʾarṣênû</em>, "so that glory may dwell in our land!") — <em>kābôd</em>: the divine glory (the <em>kābôd YHWH</em> that filled the tabernacle — Exod 40:34-35 — and the temple — 1 Kgs 8:11 — and departed in the crisis of Ezek 10-11). The petition: may the glory that departed return and dwell (<em>shākan</em>). Ezek 43:1-5 promises its return. John 1:14 declares fulfillment: "the Word... tabernacled (<em>ἐσκήνωσεν</em>) among us, and we saw his glory (<em>δόξαν</em>)."</p>',
    "10": '<p><strong>חֶסֶד-וֶאֱמֶת נִפְגָּשׁוּ צֶדֶק וְשָׁלוֹם נָשָׁקוּ</strong> (<em>ḥesed-wĕʾĕmet nipgāshû ṣedeq wĕshālôm nāshāqû</em>, "steadfast love and faithfulness meet; righteousness and peace kiss!") — the most celebrated verse of Psalm 85, one of the great theological lines of the Psalter. Four divine covenant attributes personified as figures who meet and embrace. <em>Nifgash</em> (niphal of <em>pāgash</em>: to meet, to encounter — as in Exod 4:24 where YHWH "met" Moses): <em>ḥesed</em> (covenant love) and <em>ʾĕmet</em> (faithfulness/truth — the two paired throughout: Ps 89:14; Gen 24:27) meeting in greeting. <em>Nāshaq</em>: to kiss (Gen 29:11; 45:15): <em>ṣedeq</em> (righteousness — the divine right-making, the justification) and <em>shālôm</em> (peace — the wholeness of restored relationship) kissing. Luther saw this as a prophecy of the incarnation: "Where could these four attributes meet except at the cross, where love and faithfulness met in the sacrifice of the Son, and righteousness and peace kissed in the reconciliation of God and humanity?" The verse is not allegory — it is the covenant vision of reality restored.</p>',
    "11": '<p><strong>אֱמֶת מֵאֶרֶץ תִּצְמָח</strong> (<em>ʾĕmet mêʾereṣ tiṣmaḥ</em>, "faithfulness springs up from the earth!") — <em>ṣāmaḥ</em>: to sprout, to spring up (the agricultural verb for vegetation breaking through — Isa 45:8: "let righteousness spring up from the earth"). <em>ʾĔmet</em>: faithfulness/truth rising from the ground — the covenant faithfulness of the human community responding to the divine character. <strong>וְצֶדֶק מִשָּׁמַיִם נִשְׁקָף</strong> (<em>wĕṣedeq mishshāmayim nishqāp</em>, "and righteousness looks down from heaven!") — <em>nishqāp</em> (niphal of <em>shāqap</em>: to look down from a height — Num 21:20; Gen 26:8). Heaven and earth in exchange: faithfulness rising from below; righteousness gazing down from above — the mutual meeting of human and divine in covenant fulfillment.</p>',
    "12": '<p><strong>גַּם-יְהוָה יִתֵּן הַטּוֹב</strong> (<em>gam-yĕhwāh yittên haṭṭôb</em>, "yes, the LORD will give what is good!") — <em>haṭṭôb</em>: the good (with the definite article: the specific covenantal good that belongs to restoration — Ps 84:11: "no good thing does he withhold"). <strong>וְאַרְצֵנוּ תִּתֵּן יְבוּלָהּ</strong> (<em>wĕʾarṣênû tittên yĕbûlāh</em>, "and our land will yield its harvest!") — <em>yĕbûl</em>: the produce, the yield (Lev 26:4,20; Deut 11:17 — harvest as the sign of covenant blessing or its absence). The restoration of v1 (God showed favor to the land) now extends to productive abundance: the land gives back what the curse had withheld.</p>',
    "13": '<p><strong>צֶדֶק לְפָנָיו יְהַלֵּךְ</strong> (<em>ṣedeq lĕpānāyw yĕhallêk</em>, "righteousness will march before him!") — <em>ṣedeq</em> personified as the divine advance-guard: the one who goes before the divine warrior to prepare the way (as the ark went before Israel — Num 10:33; Josh 3:6). The image of divine righteousness as forerunner/herald: Isa 58:8 ("your righteousness will go before you"); Isa 45:8 ("let righteousness spring up from the earth"). Paul\'s declaration in Rom 1:17 that the righteousness of God is being revealed (<em>ἀποκαλύπτεται δικαιοσύνη θεοῦ</em>) in the gospel echoes this precise imagery — the advance of divine <em>ṣedeq</em> into human history. <strong>וְיָשֵׂם לְדֶרֶךְ פְּעָמָיו</strong> (<em>wĕyāśêm lĕderek pĕʿāmāyw</em>, "and prepare a path for his steps!") — <em>pĕʿāmîm</em>: footsteps, the rhythmic advance of God\'s march into his restored world. Righteousness clears the road and lays the path for the divine arrival — the psalm that began by remembering a past restoration ends looking forward to the final arrival of God himself, preceded by his righteousness as herald.</p>',
  },
}


def main():
    existing = load_comm('mkt-original', 'psalms')
    merge_comm(existing, PSALMS)
    save_comm('mkt-original', 'psalms', existing)
    print('Psalms 80-85 mkt-original written.')

if __name__ == '__main__':
    main()
